  "data-[state=closed]:animate-out data-[state=closed]:fade-out-0",
  "data-[state=open]:animate-in data-[state=open]:fade-in-0",
  className
)}
```

```typescript
// form.tsx - conditional data attributes
<Label
  data-slot="form-label"
  data-error={!!error}
  className={cn("data-[error=true]:text-destructive", className)}
/>
```

---

### 9. **Radix UI Slot Component Pattern**

shadcn/ui uses Radix's `Slot` component to allow "asChild" composition:

```typescript
// sidebar.tsx
function SidebarGroupLabel({
  className,
  asChild = false,
  ...props
}: React.ComponentProps<"div"> & { asChild?: boolean }) {
  const Comp = asChild ? Slot.Root : "div"

  return (
    <Comp
      data-slot="sidebar-group-label"
      className={cn(...)}
      {...props}
    />
  )
}

// breadcrumb.tsx
function BreadcrumbLink({
  asChild,
  className,
  ...props
}: React.ComponentProps<"a"> & {
  asChild?: boolean
}) {
  const Comp = asChild ? Slot.Root : "a"

  return (
    <Comp
      data-slot="breadcrumb-link"
      className={cn("transition-colors hover:text-foreground", className)}
      {...props}
    />
  )
}

// button.tsx
function Button({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "button"

  return (
    <Comp
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size }), className)}
      {...props}
    />
  )
}
```

**Benefits:**
- Polymorphic component rendering
- Merges props from parent and child
- Maintains styling chain
- Example: `<BreadcrumbLink asChild><a href="/"></BreadcrumbLink>`

---

### 10. **Provider Component Pattern**

Complex components use provider wrappers to manage context:

```typescript
// carousel.tsx - Simple provider
function Carousel({
  orientation = "horizontal",
  opts,
  setApi,
  plugins,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & CarouselProps) {
  const [carouselRef, api] = useEmblaCarousel({...})
  const [canScrollPrev, setCanScrollPrev] = React.useState(false)
  const [canScrollNext, setCanScrollNext] = React.useState(false)

  // Setup effects and callbacks
  React.useEffect(() => {...}, [api, setApi])
  React.useEffect(() => {...}, [api, onSelect])

  return (
    <CarouselContext.Provider
      value={{
        carouselRef,
        api: api,
        opts,
        orientation,
        scrollPrev,
        scrollNext,
        canScrollPrev,
        canScrollNext,
      }}
    >
      <div data-slot="carousel" {...props}>
        {children}
      </div>
    </CarouselContext.Provider>
  )
}
```

```typescript
// sidebar.tsx - Complex provider with TooltipProvider nesting
function SidebarProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange: setOpenProp,
  className,
  style,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
}) {
  const isMobile = useIsMobile()
  const [openMobile, setOpenMobile] = React.useState(false)
  const [_open, _setOpen] = React.useState(defaultOpen)

  const contextValue = React.useMemo<SidebarContextProps>(
    () => ({
      state,
      open,
      setOpen,
      isMobile,
      openMobile,
      setOpenMobile,
      toggleSidebar,
    }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
  )

  return (
    <SidebarContext.Provider value={contextValue}>
      <TooltipProvider delayDuration={0}>
        <div
          data-slot="sidebar-wrapper"
          style={{
            "--sidebar-width": SIDEBAR_WIDTH,
            "--sidebar-width-icon": SIDEBAR_WIDTH_ICON,
            ...style,
          } as React.CSSProperties}
          {...props}
        >
          {children}
        </div>
      </TooltipProvider>
    </SidebarContext.Provider>
  )
}
```

**Key patterns:**
- Use `React.useMemo` to memoize context value and prevent unnecessary re-renders
- Support both controlled (`openProp`/`setOpenProp`) and uncontrolled (`_open`/`_setOpen`) modes
- Use `useCallback` for handler functions that are passed in context

---

### 11. **Export Pattern**

All components are exported as named exports at the end:

```typescript
// carousel.tsx
export {
  type CarouselApi,
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselPrevious,
  CarouselNext,
}

// tabs.tsx
export { Tabs, TabsList, TabsTrigger, TabsContent, tabsListVariants }

// sidebar.tsx
export {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupAction,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarHeader,
  SidebarInput,
  SidebarInset,
  SidebarMenu,
  SidebarMenuAction,
  SidebarMenuBadge,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarMenuSkeleton,
  SidebarMenuSub,
  SidebarMenuSubButton,
  SidebarMenuSubItem,
  SidebarProvider,
  SidebarRail,
  SidebarSeparator,
  SidebarTrigger,
  useSidebar,
}

// form.tsx
export {
  useFormField,
  Form,
  FormItem,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
  FormField,
}
```

- Types are exported with `type` prefix for clarity
- Variant types (from cva) are often exported
- Custom hooks are exported alongside components

---

### 12. **CSS Custom Properties (CSS Variables)**

Sidebar component demonstrates heavy use of CSS variables:

```typescript
<div
  data-slot="sidebar-wrapper"
  style={
    {
      "--sidebar-width": SIDEBAR_WIDTH,
      "--sidebar-width-icon": SIDEBAR_WIDTH_ICON,
      ...style,
    } as React.CSSProperties
  }
  className={cn(
    "group/sidebar-wrapper flex min-h-svh w-full has-data-[variant=inset]:bg-sidebar",
    className
  )}
>
```

Used in classNames:
```typescript
className={cn(
  "relative w-(--sidebar-width) bg-transparent transition-[width] duration-200 ease-linear",
  "group-data-[collapsible=offcanvas]:w-0"
)}
```

---

### 13. **Compound Component Structure Summary**

A typical shadcn compound component has this structure:

```
1. "use client" directive (if using hooks/context)
2. Imports (React, Radix, cva, cn, icons, etc.)
3. Type definitions for context props
4. Context creation with React.createContext
5. Custom hook to consume context (with error checking)
6. Helper functions (generateId, etc.)
7. Variant definitions using cva (if applicable)
8. Provider component (if needed)
9. Sub-components (Content, Item, Trigger, etc.)
10. Export statement with all public members
```

---

### 14. **File Locations Reference**

- `/apps/v4/registry/new-york-v4/ui/carousel.tsx` - Context + Embla carousel example
- `/apps/v4/registry/new-york-v4/ui/tabs.tsx` - Radix primitive with group data selectors
- `/apps/v4/registry/new-york-v4/ui/accordion.tsx` - Simple Radix wrapper
- `/apps/v4/registry/new-york-v4/ui/sidebar.tsx` - Complex multi-context provider
- `/apps/v4/registry/new-york-v4/ui/form.tsx` - Multiple nested contexts with react-hook-form
- `/apps/v4/registry/new-york-v4/ui/button.tsx` - cva + Slot pattern
- `/apps/v4/registry/new-york-v4/ui/dialog.tsx` - Portal-based component
- `/apps/v4/registry/new-york-v4/ui/breadcrumb.tsx` - Simple composition (no context)
- `/apps/v4/lib/utils.ts` - The `cn()` utility implementation

---

This architecture demonstrates React best practices for scalable, maintainable component libraries with excellent TypeScript support and composition flexibility.

