"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { title: "Account", description: "Set up your account details." },
  { title: "Profile", description: "Customize your profile information." },
  { title: "Complete", description: "Review and finish the setup." },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-lg flex-col gap-6">
      <Stepper activeStep={activeStep}>
        {steps.map((step, index) => (
          <React.Fragment key={step.title}>
            <StepperItem step={index}>
              <StepperTrigger onClick={() => setActiveStep(index)} />
              <StepperTitle>{step.title}</StepperTitle>
            </StepperItem>
            {index < steps.length - 1 && (
              <StepperSeparator />
            )}
          </React.Fragment>
        ))}
      </Stepper>
      {steps.map((step, index) => (
        <StepperContent key={step.title} step={index}>
          <div className="rounded-lg border p-4">
            <h3 className="text-lg font-medium">{step.title}</h3>
            <p className="text-sm text-muted-foreground">
              {step.description}
            </p>
          </div>
        </StepperContent>
      ))}
      <div className="flex justify-between">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(0, prev - 1))}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length - 1, prev + 1))
          }
          disabled={activeStep === steps.length - 1}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

